#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
typedef long long ll;int a[55],m;ll dp[55][2][55][2],n;
inline ll Solve(ll n)
{
	if(n<=1)return 0;m=0;memset(dp,0,sizeof(dp));
	while(n)a[++m]=n&1,n>>=1;
	dp[1][0][0][0]=dp[1][1][1][0]=1;
	if(a[1])dp[1][1][1][1]=1;dp[1][0][0][1]=1;
	rep(1,m-1,d)
	{
		rep(0,d,j)
		{
			rep(0,1,gg)
			{
				dp[d+1][1][j+1][0]+=dp[d][gg][j][0];
				dp[d+1][0][j][0]+=dp[d][gg][j][0];
				if(a[d+1]==0)
				{
					dp[d+1][0][j][1]+=dp[d][gg][j][1];
				}
				else
				{
					dp[d+1][0][j][1]+=dp[d][gg][j][0];
					dp[d+1][1][j+1][1]+=dp[d][gg][j][1];
				}
			}
		}
	}
	ll ans=0;rep(1,m,d){rep(0,d,i)if(d-i>=i)ans+=dp[d][1][i][d==m];}return ans;
}
int main()
{
	ll L,R;scanf("%lld%lld",&L,&R);
	printf("%lld\n",Solve(R)-Solve(L-1));
}
